import java.util.Calendar

class Bad {
    fun schedule() { val cal = Calendar.getInstance() }
}

import java.util.Calendar
import java.util.Locale

class Bad {
    fun schedule() { val cal = Calendar.getInstance(Locale.US) }
}

import java.util.GregorianCalendar

class Bad {
    fun schedule() { val cal = GregorianCalendar() }
}

import java.util.Calendar
import java.util.Locale
import java.util.TimeZone

class Bad {
    fun schedule() { val cal = Calendar.getInstance(TimeZone.getTimeZone("UTC"), Locale.US) }
}

import java.time.Instant

class Good {
    fun now(): Instant = Instant.now()
}

import java.time.LocalDateTime

class Good {
    fun schedule(): LocalDateTime = LocalDateTime.now()
}

import java.time.ZonedDateTime
import java.time.ZoneId

class Good {
    fun schedule(): ZonedDateTime = ZonedDateTime.now(ZoneId.of("UTC"))
}
